+<script>
+// =============================================================================
+// Terminal Renderer using Canvas 2D (GPU-accelerated on macOS)
+// =============================================================================
+
+class TerminalRenderer {
+    constructor(canvas) {
+        this.canvas = canvas;
+        this.ctx = canvas.getContext('2d', { alpha: false });
+
+        // Terminal state
+        this.cols = 80;
+        this.rows = 24;
+        this.cellWidth = 9;
+        this.cellHeight = 18;
+        this.fontFamily = 'SF Mono, Menlo, Monaco, monospace';
+        this.fontSize = 14;
+
+        // Cell buffer: [codepoint, fg_r, fg_g, fg_b, bg_r, bg_g, bg_b, flags] per cell
+        this.cells = null;
+        this.cursor = { x: 0, y: 0 };
+
+        // Colors
+        this.defaultFg = [255, 255, 255];
+        this.defaultBg = [20, 20, 26];
+
+        this.setupCanvas();
+    }
+
+    setupCanvas() {
+        const dpr = window.devicePixelRatio || 1;
+        const rect = this.canvas.parentElement.getBoundingClientRect();
+
+        this.canvas.width = rect.width * dpr;
+        this.canvas.height = rect.height * dpr;
+        this.canvas.style.width = rect.width + 'px';
+        this.canvas.style.height = rect.height + 'px';
+
+        this.ctx.scale(dpr, dpr);
+        this.ctx.font = `${this.fontSize}px ${this.fontFamily}`;
+        this.ctx.textBaseline = 'top';
+
+        // Calculate grid size
+        this.cols = Math.floor(rect.width / this.cellWidth);
+        this.rows = Math.floor(rect.height / this.cellHeight);
+
+        // Initialize empty cells
+        this.cells = new Array(this.cols * this.rows).fill(null).map(() => ({
+            char: ' ',
+            fg: [...this.defaultFg],
+            bg: [...this.defaultBg],
+            bold: false,
+            italic: false,
+            underline: false
+        }));
+
+        this.render();
+    }
+
+    // Update from packed buffer (12 bytes per cell)
+    updateFromBuffer(buffer) {
+        const view = new DataView(buffer);
+        const cellCount = Math.min(this.cells.length, buffer.byteLength / 12);
+
+        for (let i = 0; i < cellCount; i++) {
+            const offset = i * 12;
+            const codepoint = view.getUint32(offset, true);
+            const cell = this.cells[i];
+
+            cell.char = codepoint > 0 ? String.fromCodePoint(codepoint) : ' ';
+            cell.fg = [
+                view.getUint8(offset + 4),
+                view.getUint8(offset + 5),
+                view.getUint8(offset + 6)
+            ];
+            cell.bg = [
+                view.getUint8(offset + 7),
+                view.getUint8(offset + 8),
+                view.getUint8(offset + 9)
+            ];
+
+            const flags = view.getUint16(offset + 10, true);
+            cell.bold = (flags & 1) !== 0;
+            cell.italic = (flags & 2) !== 0;
+            cell.underline = (flags & 4) !== 0;
+        }
+
+        this.render();
+    }
+
+    // Append text (simple mode for LLM output)
+    appendText(text) {
+        for (const char of text) {
+            if (char === '\n') {
+                this.cursor.x = 0;
+                this.cursor.y++;
+                if (this.cursor.y >= this.rows) {
+                    this.scroll();
+                    this.cursor.y = this.rows - 1;
+                }
+            } else if (char === '\r') {
+                this.cursor.x = 0;
+            } else {
+                if (this.cursor.x >= this.cols) {
+                    this.cursor.x = 0;
+                    this.cursor.y++;
+                    if (this.cursor.y >= this.rows) {
+                        this.scroll();
+                        this.cursor.y = this.rows - 1;
+                    }
+                }
+                const idx = this.cursor.y * this.cols + this.cursor.x;
+                if (idx < this.cells.length) {
+                    this.cells[idx].char = char;
+                    this.cells[idx].fg = [...this.defaultFg];
+                    this.cells[idx].bg = [...this.defaultBg];
+                }
+                this.cursor.x++;
+            }
+        }
+        this.render();
+    }
+
+    scroll() {
+        // Move all rows up by one
+        for (let y = 0; y < this.rows - 1; y++) {
+            for (let x = 0; x < this.cols; x++) {
+                const srcIdx = (y + 1) * this.cols + x;
+                const dstIdx = y * this.cols + x;
+                this.cells[dstIdx] = { ...this.cells[srcIdx] };
+            }
+        }
+        // Clear last row
+        for (let x = 0; x < this.cols; x++) {
+            const idx = (this.rows - 1) * this.cols + x;
+            this.cells[idx] = {
+                char: ' ',
+                fg: [...this.defaultFg],
+                bg: [...this.defaultBg],
+                bold: false, italic: false, underline: false
+            };
+        }
+    }
+
+    clear() {
+        for (const cell of this.cells) {
+            cell.char = ' ';
+            cell.fg = [...this.defaultFg];
+            cell.bg = [...this.defaultBg];
+            cell.bold = false;
+            cell.italic = false;
+            cell.underline = false;
+        }
+        this.cursor = { x: 0, y: 0 };
+        this.render();
+    }
+
+    render() {
+        const ctx = this.ctx;
+        const rect = this.canvas.parentElement.getBoundingClientRect();
+
+        // Clear with background
+        ctx.fillStyle = `rgb(${this.defaultBg.join(',')})`;
+        ctx.fillRect(0, 0, rect.width, rect.height);
+
+        // Draw cells
+        for (let y = 0; y < this.rows; y++) {
+            for (let x = 0; x < this.cols; x++) {
+                const idx = y * this.cols + x;
+                const cell = this.cells[idx];
+                if (!cell) continue;
+
+                const px = x * this.cellWidth;
+                const py = y * this.cellHeight;
+
+                // Background
+                if (cell.bg[0] !== this.defaultBg[0] ||
+                    cell.bg[1] !== this.defaultBg[1] ||
+                    cell.bg[2] !== this.defaultBg[2]) {
+                    ctx.fillStyle = `rgb(${cell.bg.join(',')})`;
+                    ctx.fillRect(px, py, this.cellWidth, this.cellHeight);
+                }
+
+                // Character
+                if (cell.char && cell.char !== ' ') {
+                    let fontStyle = '';
+                    if (cell.bold) fontStyle += 'bold ';
+                    if (cell.italic) fontStyle += 'italic ';
+                    ctx.font = `${fontStyle}${this.fontSize}px ${this.fontFamily}`;
+                    ctx.fillStyle = `rgb(${cell.fg.join(',')})`;
+                    ctx.fillText(cell.char, px, py + 2);
+                }
+
+                // Underline
+                if (cell.underline) {
+                    ctx.strokeStyle = `rgb(${cell.fg.join(',')})`;
+                    ctx.lineWidth = 1;
+                    ctx.beginPath();
+                    ctx.moveTo(px, py + this.cellHeight - 2);
+                    ctx.lineTo(px + this.cellWidth, py + this.cellHeight - 2);
+                    ctx.stroke();
+                }
+            }
+        }
+
+        // Draw cursor
+        const cursorX = this.cursor.x * this.cellWidth;
+        const cursorY = this.cursor.y * this.cellHeight;
+        ctx.fillStyle = 'rgba(255, 255, 255, 0.7)';
+        ctx.fillRect(cursorX, cursorY, 2, this.cellHeight);
+    }
+}
+
+// =============================================================================
+// App Controller
+// =============================================================================
+
+const terminal = new TerminalRenderer(document.getElementById('terminal'));
+const prompt = document.getElementById('prompt');
+const sendBtn = document.getElementById('send-btn');
+const statusDot = document.getElementById('status-dot');
+const statusText = document.getElementById('status-text');
+const modelSelect = document.getElementById('model-select');
+
+let isProcessing = false;
+
+// Handle window resize
+window.addEventListener('resize', () => terminal.setupCanvas());
+
+// Handle keyboard shortcuts
+prompt.addEventListener('keydown', (e) => {
+    if (e.metaKey && e.key === 'Enter') {
+        e.preventDefault();
+        sendPrompt();
+    }
+});
+
+sendBtn.addEventListener('click', sendPrompt);
+
+function sendPrompt() {
+    if (isProcessing || !prompt.value.trim()) return;
+
+    const text = prompt.value.trim();
+    prompt.value = '';
+
+    isProcessing = true;
+    statusDot.classList.add('busy');
+    statusText.textContent = 'Thinking...';
+    sendBtn.disabled = true;
+
+    // Show user message
+    terminal.appendText('\n\x1b[1;36mYou:\x1b[0m ' + text + '\n\n');
+    terminal.appendText('\x1b[1;32mAssistant:\x1b[0m ');
+
+    // Send to Swift
+    if (window.webkit && window.webkit.messageHandlers.zell) {
+        window.webkit.messageHandlers.zell.postMessage({
+            type: 'prompt',
+            text: text,
+            model: modelSelect.value
+        });
+    }
+}
+
+// API called from Swift
+window.zellAPI = {
+    appendOutput(text) {
+        terminal.appendText(text);
+    },
+
+    complete(error) {
+        isProcessing = false;
+        statusDot.classList.remove('busy');
+        statusText.textContent = error ? 'Error' : 'Ready';
+        sendBtn.disabled = false;
+
+        if (error) {
+            terminal.appendText('\n\x1b[1;31mError:\x1b[0m ' + error + '\n');
+        } else {
+            terminal.appendText('\n');
+        }
+    },
+
+    setModels(models) {
+        modelSelect.innerHTML = '';
+        for (const model of models) {
+            const opt = document.createElement('option');
+            opt.value = model;
+            opt.textContent = model.split('/').pop();
+            modelSelect.appendChild(opt);
+        }
+    },
+
+    clear() {
+        terminal.clear();
+    },
+
+    updateFromBuffer(buffer) {
+        terminal.updateFromBuffer(buffer);
+    }
+};
+
+// Welcome message
+terminal.appendText('Welcome to Zell!\n\n');
+</script>
+</body>
+</html>

