+//! Terminal emulator wrapper using Ghostty's VT parser
+//!
+//! This module wraps Ghostty's terminal emulation to parse ANSI/VT sequences
+//! and maintain screen state. The cell grid is exposed via C ABI for Swift/WebKit.
+
+const std = @import("std");
+const Allocator = std.mem.Allocator;
+
+// Import Ghostty terminal components via lib_vt
+const ghostty = @import("ghostty_terminal");
+const Terminal = ghostty.Terminal;
+const Screen = ghostty.Screen;
+const RenderState = ghostty.RenderState;
+const Cell = ghostty.Cell;
+const Style = ghostty.Style;
+const Stream = ghostty.Stream;
+const page = ghostty.page;
+const point = ghostty.point;
+const size = ghostty.size;
+
+/// Terminal instance with screen buffer
+pub const ZellTerminal = struct {
+    allocator: Allocator,
+    terminal: *Terminal,
+    render_state: RenderState,
+    cols: size.CellCountInt,
+    rows: size.CellCountInt,
+
+    const Self = @This();
+
+    pub fn init(allocator: Allocator, cols: size.CellCountInt, rows: size.CellCountInt) !*Self {
+        const self = try allocator.create(Self);
+        errdefer allocator.destroy(self);
+
+        self.* = .{
+            .allocator = allocator,
+            .terminal = try Terminal.init(allocator, .{
+                .cols = cols,
+                .rows = rows,
+            }),
+            .render_state = RenderState.empty,
+            .cols = cols,
+            .rows = rows,
+        };
+        return self;
+    }
+
+    pub fn deinit(self: *Self) void {
+        self.render_state.deinit(self.allocator);
+        self.terminal.deinit(self.allocator);
+        self.allocator.destroy(self);
+    }
+
+    /// Feed data through VT parser
+    pub fn feed(self: *Self, data: []const u8) !void {
+        // Create a stream that uses terminal as handler
+        var stream = Stream(*Terminal).initAlloc(self.allocator, self.terminal);
+        try stream.nextSlice(data);
+    }
+
+    /// Update render state for reading cells
+    pub fn updateRenderState(self: *Self) !void {
+        try self.render_state.update(self.allocator, self.terminal);
+    }
+
+    /// Resize terminal
+    pub fn resize(self: *Self, cols: size.CellCountInt, rows: size.CellCountInt) !void {
+        try self.terminal.resize(.{
+            .cols = cols,
+            .rows = rows,
+        });
+        self.cols = cols;
+        self.rows = rows;
+    }
+
+    /// Get cursor position
+    pub fn getCursor(self: *Self) struct { x: size.CellCountInt, y: size.CellCountInt } {
+        return .{
+            .x = self.render_state.cursor.active.x,
+            .y = self.render_state.cursor.active.y,
+        };
+    }
+};
+
+/// Cell information for C ABI export
+pub const CellInfo = extern struct {
+    codepoint: u32,
+    fg_r: u8,
+    fg_g: u8,
+    fg_b: u8,
+    bg_r: u8,
+    bg_g: u8,
+    bg_b: u8,
+    flags: u8, // bit 0: bold, bit 1: italic, bit 2: underline
+};
