+/// Get entire screen as packed buffer for efficient transfer to WebKit
+/// Format per cell (12 bytes): codepoint(4) + fg_rgb(3) + bg_rgb(3) + flags(2)
+export fn zell_terminal_get_screen_buffer(term: *ZellTerminal, out: [*]u8, max_len: usize) usize {
+    const bytes_per_cell = 12;
+    const total_cells = @as(usize, term.cols) * @as(usize, term.rows);
+    const needed = total_cells * bytes_per_cell;
+
+    if (max_len < needed) return 0;
+
+    // Update render state first
+    term.updateRenderState() catch return 0;
+
+    var offset: usize = 0;
+    const row_data = term.render_state.row_data;
+    const cells_slice = row_data.items(.cells);
+
+    for (cells_slice) |cells| {
+        const raw_cells = cells.items(.raw);
+        const styles = cells.items(.style);
+
+        for (raw_cells, styles) |raw, style| {
+            // Codepoint (4 bytes)
+            const cp: u32 = if (raw.content_tag == .codepoint)
+                raw.content.codepoint
+            else
+                ' ';
+            std.mem.writeInt(u32, out[offset..][0..4], cp, .little);
+            offset += 4;
+
+            // FG color (3 bytes)
+            const fg = style.fg_color orelse ghostty.color.RGB{ .r = 255, .g = 255, .b = 255 };
+            out[offset] = fg.r;
+            out[offset + 1] = fg.g;
+            out[offset + 2] = fg.b;
+            offset += 3;
+
+            // BG color (3 bytes)
+            const bg = style.bg_color orelse ghostty.color.RGB{ .r = 0, .g = 0, .b = 0 };
+            out[offset] = bg.r;
+            out[offset + 1] = bg.g;
+            out[offset + 2] = bg.b;
+            offset += 3;
+
+            // Flags (2 bytes)
+            var flags: u16 = 0;
+            if (style.flags.bold) flags |= 1;
+            if (style.flags.italic) flags |= 2;
+            if (style.flags.underline != .none) flags |= 4;
+            std.mem.writeInt(u16, out[offset..][0..2], flags, .little);
+            offset += 2;
+        }
+    }
+
+    return offset;
+}
